// Pre-Proceso v6: lee custom fields por ID real de GHL
// IDs descubiertos manualmente:
// Score = UYsnUGzSppmFWJcVFcz6
// Bloque Actual = koxarQF3nqPVH2imJj0R
// Resultado = OyWo0TP2py4acLQGhKPk

const FIELD_IDS = {
  score: 'UYsnUGzSppmFWJcVFcz6',
  bloque_actual: 'koxarQF3nqPVH2imJj0R',
  resultado: 'OyWo0TP2py4acLQGhKPk'
};

for (const item of $input.all()) {
  const wb = $('Webhook').item.json.body || {};

  let ghlContact = {};
  try {
    ghlContact = $('GHL — Get Contact').item.json.contact || $('GHL — Get Contact').item.json || {};
  } catch(e) {
    ghlContact = {};
  }

  // Extraer custom fields por ID
  const cf = {};
  if (ghlContact.customFields && Array.isArray(ghlContact.customFields)) {
    for (const field of ghlContact.customFields) {
      cf[field.id] = field.value || field.field_value || '';
    }
  }

  // Leer valores usando IDs reales
  const scoreAnterior   = parseInt(cf[FIELD_IDS.score] || 0, 10);
  const bloqueAnterior  = cf[FIELD_IDS.bloque_actual] || "0B";
  const resultadoAnterior = (cf[FIELD_IDS.resultado] || "").toLowerCase();

  // Calcular tiempo desde último update (DEBE ir antes de usarlo)
  const dateUpdated = ghlContact.dateUpdated || "";
  const minutosDesdeUpdate = dateUpdated
    ? (Date.now() - new Date(dateUpdated).getTime()) / 60000
    : 999;

  // Detectar reingreso (solo si pasaron más de 5 minutos)
  const procesoTerminado = ["descartado", "élite", "elite", "calificado", "potencial"].includes(resultadoAnterior);
  const esReingreso = procesoTerminado && minutosDesdeUpdate > 5;

  // Calcular horas de abandono
  const ctxAbandonoHoras = dateUpdated
    ? Math.round((Date.now() - new Date(dateUpdated).getTime()) / 3600000)
    : 0;

  // Exportar
  item.json.ctx_score_acumulado    = esReingreso ? 0 : scoreAnterior;
  item.json.ctx_current_block      = esReingreso ? "0B" : (bloqueAnterior || "0B");
  item.json.ctx_abandono_horas     = ctxAbandonoHoras;
  item.json.ctx_es_reingreso       = esReingreso;
  item.json.ctx_turn_count         = 0;
  item.json.ctx_mensaje            = wb.message?.body || "";
  item.json.ctx_first_name         = wb.first_name || ghlContact.firstName || "";
  item.json.ctx_last_name          = wb.last_name || ghlContact.lastName || "";
  item.json.ctx_contact_id         = wb.contact_id || "";
  item.json.ctx_phone              = wb.phone || ghlContact.phone || "";
}
return $input.all();

