for (const item of $input.all()) {
  let aiData = {};

  // Parseo del output del AI Agent
  try {
    const rawOutput = item.json.output || item.json.text || "";
    let clean = rawOutput.replace(/```json/g, '').replace(/```/g, '').trim();
    const match = clean.match(/\{[\s\S]*\}/);
    if (match) aiData = JSON.parse(match[0]);
  } catch (e) {
    item.json.parse_error = true;
  }

  const cd = aiData.candidate_data || {};
  const wb = $('Webhook').item.json.body || {};

  const firstName = cd.first_name || wb.first_name || "";
  const lastName  = cd.last_name  || wb.last_name  || "";
  const phone     = wb.phone || "";
  const aiStatus  = (aiData.status || "en_progreso").toLowerCase();

  // Construir link de la app con nombre y teléfono
  const appLink = `https://rrhh.magnetraffic.com/evaluate?name=${encodeURIComponent((firstName + ' ' + lastName).trim())}&phone=${encodeURIComponent(phone)}`;

  // Reemplazar [APP_LINK] y [NOMBRE] en los mensajes
  const candidateName = firstName || "Hola";

  item.json.ai_reply_1 = (aiData.replies?.[0] || "")
    .replace(/\[NOMBRE\]/g, candidateName)
    .replace(/\[APP_LINK\]/g, appLink);

  item.json.ai_reply_2 = (aiData.replies?.[1] || "")
    .replace(/\[NOMBRE\]/g, candidateName)
    .replace(/\[APP_LINK\]/g, appLink);

  item.json.ai_status     = aiStatus;
  item.json.current_block = aiData.current_block || "0B";
  item.json.ghl_first_name = firstName;
  item.json.ghl_last_name  = lastName;

  // Body para actualizar GHL
  const updateBody = {
    customFields: [
      { id: 'koxarQF3nqPVH2imJj0R', field_value: aiData.current_block || "0B" },
      {
        id: 'OyWo0TP2py4acLQGhKPk',
        field_value: aiStatus === 'pre_calificado' ? 'Pre-calificado' :
                     aiStatus === 'descartado'     ? 'Descartado'     : 'En Proceso'
      }
    ]
  };

  if (firstName) updateBody.firstName = firstName;
  if (lastName)  updateBody.lastName  = lastName;

  item.json.ghl_update_body = JSON.stringify(updateBody);
}

return $input.all();

